+            is_connect: false,
+            is_request: false,
+        };
+        let json = serde_json::to_string(&info).unwrap();
+        let back: HttpErrorInfo = serde_json::from_str(&json).unwrap();
+        assert!(!back.is_timeout);
+        assert!(!back.is_connect);
+        assert!(!back.is_request);
+        assert_eq!(info, back);
+    }
